                browser_rpc_url: state.browser_rpc_url(),
            },
            endpoint.and_then(|ep| ep.description.as_deref()),
        ),
        Some(auth_value) => {
            handle_charge_authorization(
                &mpps,
                auth_value,
                subdomain,
                &path,
                state.fee_payer_wallet().cloned(),
                req,
                next,
            )
            .await
        }
    }
}

