1	//! `pay catalog check` — read-only validation of provider PAY.md files.
2	//!
3	//! Three modes, auto-detected from the positional path:
4	//!   1. **Single-file** (`<path>` is a `.md` / `PAY.md`): parse + frontmatter
5	//!      validate + probe + Solana verdict. Local devex.
6	//!   2. **CI diff** (`--changed-from <REF>`): same pipeline, scoped to
7	//!      provider files changed in the diff. `--format github` emits Actions
8	//!      annotations. Used by PR CI.
9	//!   3. **Full registry** (`<path>` is a directory, no `--changed-from`):
10	//!      walk the registry, run the check pipeline on every provider.
11	//!
12	//! Never writes to disk. Use `pay catalog build` to also produce `dist/`.
13	
14	use std::path::{Path, PathBuf};
15	
16	use clap::ValueEnum;
17	use owo_colors::OwoColorize;
18	
19	use pay_core::skills::probe::{ProbeConfig, ProbeReport};
20	
21	use super::derive_fqn_from_path;
22	use super::probe::{
23	    collect_all_providers, collect_specific_providers, parse_single_provider, render_probe_table,
24	    run_probe,
25	};
26	use super::verdict::{
27	    ValidationReport, git_changed_provider_files, render_verdict_github, render_verdict_json,
28	    render_verdict_table, validate_report,
29	};
30	use crate::components::{NoticeLevel, print_notice};
31	
32	/// Output format for verdict + probe data when `--format` is set. Defaults to
33	/// `table` (human-readable). `json` dumps machine-readable output and
34	/// suppresses the trailing notice. `github` emits Actions annotations.
35	#[derive(Debug, Clone, ValueEnum)]
36	pub enum ReportFormat {
37	    Table,
38	    Json,
39	    Github,
40	}
41	
42	#[derive(clap::Args)]
43	pub struct CheckCommand {
44	    /// Either a registry root, or a single `PAY.md` / `<name>.md` file. When
45	    /// pointed at a file, the FQN is derived from the path's parent
46	    /// directories (e.g. `quicknode/rpc/PAY.md` → fqn `quicknode/rpc`).
47	    #[arg(default_value = ".")]
48	    pub path: PathBuf,
49	
50	    // ── Probe knobs ──────────────────────────────────────────────────────
51	    /// Skip live probing of endpoints (fast frontmatter-only check).
52	    #[arg(long)]
53	    pub no_probe: bool,
54	
55	    /// Per-endpoint probe timeout in seconds.
56	    #[arg(long, default_value_t = 10)]
57	    pub probe_timeout: u64,
58	
59	    /// Max concurrent provider probes.
60	    #[arg(long, default_value_t = 5)]
61	    pub probe_concurrency: usize,
62	
63	    /// Accepted stablecoin symbols (comma-separated). An endpoint that
64	    /// advertises a non-listed currency is treated as `wrong_currency` for
65	    /// verdict purposes.
66	    #[arg(long, default_value = "USDC,USDT", value_delimiter = ',')]
67	    pub currencies: Vec<String>,
68	
69	    // ── Verdict knobs ────────────────────────────────────────────────────
70	    /// Treat every non-Solana endpoint as a blocking error (default: warn).
71	    #[arg(long)]
72	    pub strict: bool,
73	
74	    /// Verdict output format. `github` emits Actions `::warning::` / `::error::`
75	    /// annotations; `json` dumps the structured report and suppresses the
76	    /// trailing notice.
77	    #[arg(long, default_value = "table", value_enum)]
78	    pub format: ReportFormat,
79	
80	    /// Print the per-provider, per-endpoint probe + verdict breakdown in
81	    /// addition to the summary notice. Helpful when debugging a single
82	    /// provider; noisy in registry mode.
83	    #[arg(long, short = 'v')]
84	    pub verbose: bool,
85	
86	    /// Also write a GitHub-flavored markdown summary to this path
87	    /// (regardless of `--format`). Lets PR CI emit inline annotations
88	    /// *and* a tidy step-summary table from a single probe run, instead
89	    /// of re-probing every endpoint just to get a different output shape.
90	    /// Workflows append this file to `$GITHUB_STEP_SUMMARY`.
91	    #[arg(long, value_name = "PATH")]
92	    pub summary_out: Option<PathBuf>,
93	
94	    // ── Diff modes ──────────────────────────────────────────────────────
95	    /// Specific provider PAY.md files to check (relative to the registry root
96	    /// when `path` is a directory, absolute otherwise). Used by CI to pass a
97	    /// pre-computed list without requiring `git` in the runtime container.
98	    /// Mutually exclusive with `--changed-from`.
99	    #[arg(long, value_name = "PATH", num_args = 1.., conflicts_with = "changed_from")]
100	    pub files: Vec<PathBuf>,
101	
102	    /// Git ref to diff against; checks providers whose `PAY.md` (or any
103	    /// sidecar under their directory) changed between `<REF>` and `HEAD`.
104	    /// Local-devex shortcut — requires `git` on `$PATH`. CI should use
105	    /// `--files` instead.
106	    #[arg(long, value_name = "REF")]
107	    pub changed_from: Option<String>,
108	}
109	
110	impl CheckCommand {
111	    pub fn run(self) -> pay_core::Result<()> {
112	        let canonical = self.path.canonicalize().map_err(|e| {
113	            pay_core::Error::Config(format!("invalid path `{}`: {e}", self.path.display()))
114	        })?;
115	
116	        if canonical.is_file() {
117	            if self.changed_from.is_some() || !self.files.is_empty() {
118	                return Err(pay_core::Error::Config(
119	                    "--changed-from / --files require a registry directory, not a single file"
120	                        .into(),
121	                ));
122	            }
123	            return self.run_single_file(&canonical);
124	        }
125	
126	        if !self.files.is_empty() {
127	            return self.run_explicit_files(&canonical);
128	        }
129	
130	        if self.changed_from.is_some() {
131	            return self.run_changed_from(&canonical);
132	        }
133	
134	        self.run_full_registry(&canonical)
135	    }
136	
137	    fn probe_config(&self) -> ProbeConfig {
138	        ProbeConfig {
139	            accepted_currencies: self.currencies.iter().map(|c| c.to_uppercase()).collect(),
140	            timeout_secs: self.probe_timeout,
141	            concurrency: self.probe_concurrency,
142	        }
143	    }
144	
145	    // ── Mode 1: single file ─────────────────────────────────────────────
146	
147	    fn run_single_file(self, path: &Path) -> pay_core::Result<()> {
148	        let (fqn, name, operator, origin) = derive_fqn_from_path(path)?;
149	
150	        // Frontmatter + endpoint validation via the build core. Aborts before
151	        // probing if the YAML/category/length checks fail — no point probing
152	        // a file that's syntactically broken.
153	        let options = pay_core::skills::build::BuildOptions {
154	            probe: false,
155	            probe_config: ProbeConfig::default(),
156	            only: None,
157	            previous_dist: None,
158	        };
159	        let validation_only = pay_core::skills::build::build_single_provider(
160	            path, &fqn, &name, &operator, &origin, &options,
161	        );
162	        if !validation_only.errors.is_empty() {
163	            print_validation_errors(&validation_only.errors);
164	            std::process::exit(1);
165	        }
166	
167	        let provider = parse_single_provider(path)?;
168	        let endpoint_count = provider.endpoints.len();
169	
170	        if self.no_probe {
171	            print_notice(
172	                NoticeLevel::Success,
173	                "PAY.md check successful",
174	                &format!("{endpoint_count} endpoints walked, probe skipped (--no-probe)"),
175	            );
176	            return Ok(());
177	        }
178	
179	        let report = run_probe(vec![provider], &self.probe_config());
180	        let validation = validate_report(&report, self.strict);
181	
182	        self.render_verbose(&report, &validation);
183	        self.emit_summary(&report, &validation, endpoint_count, "PAY.md")
184	    }
185	
186	    // ── Mode 2a: explicit list of paths (CI) ────────────────────────────
187	
188	    fn run_explicit_files(self, root: &Path) -> pay_core::Result<()> {
189	        let files = self.files.clone();
190	        self.run_with_paths(root, &files, "Changed providers")
191	    }
192	
193	    // ── Mode 2b: changed-from (local devex; requires git on PATH) ───────
194	
195	    fn run_changed_from(self, root: &Path) -> pay_core::Result<()> {
196	        let base_ref = self.changed_from.clone().expect("checked by caller");
197	        let files = git_changed_provider_files(root, &base_ref)?;
198	        self.run_with_paths(root, &files, "Changed providers")
199	    }
200	
201	    /// Probe + verdict over a pre-computed list of provider PAY.md paths.
202	    /// Shared by `--files` and `--changed-from`.
203	    fn run_with_paths(
204	        self,
205	        root: &Path,
206	        files: &[PathBuf],
207	        title_prefix: &str,
208	    ) -> pay_core::Result<()> {
209	        if files.is_empty() {
210	            print_notice(
211	                NoticeLevel::Info,
212	                "Nothing to check",
213	                "No changed provider files.",
214	            );
215	            return Ok(());
216	        }
217	        let providers = collect_specific_providers(root, files)?;
218	        if providers.is_empty() {
219	            print_notice(
220	                NoticeLevel::Warning,
221	                "No matching providers",
222	                "Provided paths did not resolve to any registered providers.",
223	            );
224	            return Ok(());
225	        }
226	
227	        let total_endpoints: usize = providers.iter().map(|p| p.endpoints.len()).sum();
228	        if self.no_probe {
229	            print_notice(
230	                NoticeLevel::Success,
231	                &format!("{title_prefix} check successful"),
232	                &format!(
233	                    "{total_endpoints} endpoints walked across {} provider{}, probe skipped (--no-probe)",
234	                    providers.len(),
235	                    if providers.len() == 1 { "" } else { "s" },
236	                ),
237	            );
238	            return Ok(());
239	        }
240	        let report = run_probe(providers, &self.probe_config());
241	        let validation = validate_report(&report, self.strict);
242	
243	        self.render_verbose(&report, &validation);
244	        self.emit_summary(&report, &validation, total_endpoints, title_prefix)
245	    }
246	
247	    // ── Mode 3: full registry (read-only) ──────────────────────────────
248	
249	    fn run_full_registry(self, root: &Path) -> pay_core::Result<()> {
250	        let providers = collect_all_providers(root)?;
251	        if providers.is_empty() {
252	            print_notice(
253	                NoticeLevel::Warning,
254	                "Nothing to check",
255	                &format!("No provider files under {}/providers/", root.display()),
256	            );
257	            return Ok(());
258	        }
259	
260	        let total_endpoints: usize = providers.iter().map(|p| p.endpoints.len()).sum();
261	        if self.no_probe {
262	            print_notice(
263	                NoticeLevel::Success,
264	                "Registry check successful",
265	                &format!(
266	                    "{total_endpoints} endpoints walked across {} provider{}, probe skipped (--no-probe)",
267	                    providers.len(),
268	                    if providers.len() == 1 { "" } else { "s" },
269	                ),
270	            );
271	            return Ok(());
272	        }
273	        let report = run_probe(providers, &self.probe_config());
274	        let validation = validate_report(&report, self.strict);
275	
276	        self.render_verbose(&report, &validation);
277	        self.emit_summary(&report, &validation, total_endpoints, "Registry")
278	    }
279	
280	    // ── Shared rendering ────────────────────────────────────────────────
281	
282	    fn render_verbose(&self, report: &ProbeReport, validation: &ValidationReport) {
283	        if !self.verbose {
284	            return;
285	        }
286	        if matches!(self.format, ReportFormat::Json | ReportFormat::Github) {
287	            // Structured formats produce machine output; verbose tables
288	            // would mix human and machine output on the same stream.
289	            return;
290	        }
291	        eprintln!("{}", "Probe results".bold().underline());
292	        render_probe_table(report);
293	        eprintln!("{}", "Solana-compat verdict".bold().underline());
294	        render_verdict_table(validation);
295	    }
296	
297	    fn emit_summary(
298	        &self,
299	        report: &ProbeReport,
300	        validation: &ValidationReport,
301	        endpoint_count: usize,
302	        title_prefix: &str,
303	    ) -> pay_core::Result<()> {
304	        // Optional markdown sidecar — written before any potential exit
305	        // so the file is on disk even when validation blocks. PR CI cats
306	        // this into `$GITHUB_STEP_SUMMARY`.
307	        if let Some(path) = &self.summary_out {
308	            let body = render_markdown_summary(validation);
309	            std::fs::write(path, body)
310	                .map_err(|e| pay_core::Error::Config(format!("write {}: {e}", path.display())))?;
311	        }
312	
313	        match self.format {
314	            ReportFormat::Json => {
315	                render_verdict_json(validation)?;
316	                if validation.has_errors() {
317	                    std::process::exit(1);
318	                }
319	                return Ok(());
320	            }
321	            ReportFormat::Github => {
322	                render_verdict_github(validation);
323	                if validation.has_errors() {
324	                    std::process::exit(1);
325	                }
326	                return Ok(());
327	            }
328	            ReportFormat::Table => {}
329	        }
330	
331	        let stats = verdict_stats(validation);
332	        let body = stats.format(endpoint_count, report.failed);
333	
334	        if validation.has_errors() {
335	            print_notice(
336	                NoticeLevel::Error,
337	                &format!("{title_prefix} check failed"),
338	                &body,
339	            );
340	            std::process::exit(1);
341	        }
342	        let warn = !stats.is_clean();
343	        let level = if warn {
344	            NoticeLevel::Warning
345	        } else {
346	            NoticeLevel::Success
347	        };
348	        let title = if warn {
349	            format!("{title_prefix} check passed with warnings")
350	        } else {
351	            format!("{title_prefix} check successful")
352	        };
353	        print_notice(level, &title, &body);
354	        Ok(())
355	    }
356	}
357	
358	#[derive(Debug, Clone, Copy)]
359	struct VerdictStats {
360	    providers: usize,
361	    blocked: usize,
362	    ok: usize,
363	    classified: usize,
364	    non_solana: usize,
365	}
366	
367	impl VerdictStats {
368	    fn is_clean(&self) -> bool {
369	        self.blocked == 0 && self.non_solana == 0
370	    }
371	
372	    fn format(&self, endpoint_count: usize, probe_failed: usize) -> String {
373	        let mut lines = Vec::new();
374	        lines.push(format!(
375	            "{} endpoint{} tested across {} provider{}",
376	            endpoint_count,
377	            if endpoint_count == 1 { "" } else { "s" },
378	            self.providers,
379	            if self.providers == 1 { "" } else { "s" },
380	        ));
381	        if self.classified > 0 {
382	            lines.push(format!(
383	                "{}/{} gates compatible with Solana",
384	                self.ok, self.classified
385	            ));
386	        }
387	        if self.non_solana > 0 {
388	            lines.push(format!(
389	                "{} non-Solana endpoint{} flagged",
390	                self.non_solana,
391	                if self.non_solana == 1 { "" } else { "s" },
392	            ));
393	        }
394	        if self.blocked > 0 {
395	            lines.push(format!(
396	                "{} provider{} blocked (zero Solana-compatible gates)",
397	                self.blocked,
398	                if self.blocked == 1 { "" } else { "s" },
399	            ));
400	        }
401	        if probe_failed > 0 && self.classified == 0 {
402	            lines.push(format!("{probe_failed} probe failure(s) — see --verbose"));
403	        }
404	        lines.join("\n")
405	    }
406	}
407	
408	/// Render a GitHub-flavored markdown step-summary for a verdict report.
409	/// Mirrors what the previous workflow generated via Python — top-line
410	/// status, per-provider table, and per-provider details for non-Solana
411	/// endpoints.
412	fn render_markdown_summary(validation: &ValidationReport) -> String {
413	    use std::fmt::Write;
414	    let mut out = String::new();
415	    let _ = writeln!(out, "### Solana-compatibility verdict");
416	    let _ = writeln!(out);
417	
418	    let blocks = validation.providers.iter().filter(|p| p.block).count();
419	    let warns: usize = validation
420	        .providers
421	        .iter()
422	        .map(|p| p.non_solana_count)
423	        .sum();
424	    let oks: usize = validation.providers.iter().map(|p| p.ok_count).sum();
425	
426	    if blocks > 0 {
427	        let _ = writeln!(out, ":no_entry: **{blocks}** provider(s) blocked");
428	    } else if warns > 0 {
429	        let _ = writeln!(out, ":warning: {warns} non-Solana endpoint(s) flagged");
430	    } else {
431	        let _ = writeln!(
432	            out,
433	            ":white_check_mark: {oks} Solana-compatible endpoint(s)"
434	        );
435	    }
436	    let _ = writeln!(out);
437	    let _ = writeln!(out, "| Provider | OK | Non-Solana | Verdict |");
438	    let _ = writeln!(out, "|----------|----|------------|---------|");
439	    for p in &validation.providers {
440	        let v = if p.block {
441	            ":no_entry: BLOCK"
442	        } else if p.non_solana_count > 0 {
443	            ":warning: warn"
444	        } else {
445	            ":white_check_mark: pass"
446	        };
447	        let _ = writeln!(
448	            out,
449	            "| `{}` | {} | {} | {} |",
450	            p.fqn, p.ok_count, p.non_solana_count, v
451	        );
452	    }
453	    for p in &validation.providers {
454	        if p.non_solana_count == 0 {
455	            continue;
456	        }
457	        let _ = writeln!(out);
458	        let _ = writeln!(
459	            out,
460	            "<details><summary>{} — non-Solana endpoints</summary>",
461	            p.fqn
462	        );
463	        let _ = writeln!(out);
464	        let _ = writeln!(out, "| Method | Path | Status | Note |");
465	        let _ = writeln!(out, "|--------|------|--------|------|");
466	        for ep in &p.endpoints {
467	            if !matches!(ep.verdict, super::verdict::EndpointVerdict::NotSolana) {
468	                continue;
469	            }
470	            let _ = writeln!(
471	                out,
472	                "| `{}` | `{}` | `{}` | {} |",
473	                ep.method, ep.path, ep.probe_status, ep.note
474	            );
475	        }
476	        let _ = writeln!(out);
477	        let _ = writeln!(out, "</details>");
478	    }
479	    out
480	}
481	
482	fn verdict_stats(validation: &ValidationReport) -> VerdictStats {
483	    let providers = validation.providers.len();
484	    let blocked = validation.providers.iter().filter(|p| p.block).count();
485	    let ok: usize = validation.providers.iter().map(|p| p.ok_count).sum();
486	    let non_solana: usize = validation
487	        .providers
488	        .iter()
489	        .map(|p| p.non_solana_count)
490	        .sum();
491	    let classified = ok + non_solana;
492	    VerdictStats {
493	        providers,
494	        blocked,
495	        ok,
496	        classified,
497	        non_solana,
498	    }
499	}
500	
501	/// Render validation errors through the shared notice component.
502	pub(super) fn print_validation_errors(errors: &[String]) {
503	    let title = if errors.len() == 1 {
504	        "Validation error".to_string()
505	    } else {
506	        format!("{} validation errors", errors.len())
507	    };
508	    let mut body = String::new();
509	    for err in errors {
510	        let mut lines = err.trim_end().lines();
511	        if let Some(first) = lines.next() {
512	            body.push_str(&format!("- {first}\n"));
513	        }
514	        for line in lines {
515	            body.push_str(&format!("  {line}\n"));
516	        }
517	    }
518	    print_notice(NoticeLevel::Error, &title, body.trim_end());
519	}
