    #[test]
    fn parse_endpoints_prefers_summary_over_description() {
        let doc = r#"{
            "paths": {
                "/x": {
                    "get": {
                        "summary": "short summary",
                        "description": "long description"
                    }
                }
            }
        }"#;
        let endpoints = parse_endpoints(doc).unwrap();
        assert_eq!(endpoints[0].spec.description, "short summary");
