// Validate operation summaries (the text shown on the OS biometric prompt
// at payment time). Runs only on openapi-driven providers — inline
// `endpoints:` descriptions are already validated by `validate_provider`.
if let Some(doc) = &openapi_doc {
    for err in crate::skills::openapi::validate_operation_summaries(doc) {
        errors.push(format!("{fqn}: {err}"));
    }
    if errors.iter().any(|e| e.starts_with(&format!("{fqn}: "))) {
        // We pushed at least one summary error above — but only abort if
        // *only* the summary errors are present; otherwise the existing
        // flow already returned on earlier failures.
    }
